const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { steps: Step[] };

const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];

const sum = (numbers: number[]): number =>
  numbers.reduce((acc, n) => acc + n, 0);

const quote = (step: Step): { premium: number } => {
  const policyBase = sum(step.items.map(itemBasePremium));
  const total = policyBase * 1.1 + PROCESSING_FEE;
  // round up to whole G in MHPCO's favor, using epsilon to fight FP error
  return { premium: Math.ceil(total - 1e-9) };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quote) };
};

