import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword yields 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    });
    // 100 base + 10 first insurance + 5 fee = 115
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet yields 71 G (60 base + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for sword + amulet sums base premiums (160 base + 16 + 5 = 181)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // Quote: components and blocks
  it("quote for 2 runes yields 60 G (50 base + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 runes yields 71 G (60 block base + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes yields 115 G (100 base + 10 first ins + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote for 3 runes + 3 moonstones yields 120 G base + 5 fee = 125 G");

  // Quote: item-level modifiers
  it.todo("cursed sword adds 50% surcharge on item: 100 + 50 + 5 = 155 G");
  it.todo("high-enchantment sword (enchantment 5) adds 30% surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");

  // Quote: policy-level modifiers
  it.todo("long-standing customer (2+ years) gets 20% loyalty discount");
  it.todo("first insurance adds 10% initial assessment surcharge");
  it.todo("follow-up contracts get 15% discount");

  // Quote: rounding
  it.todo("rounds final premium up (in MHPCO's favor)");

  // Quote: integration
  it.todo("newcomer with cursed sword: premium 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");

  // Claim: basic
  it.todo("standard claim: damage 500 G on sword yields payout 400 G (minus deductible)");
  it.todo("claim on rune (no enchant/material): damage 200 yields 100 G payout");

  // Claim: special clauses
  it.todo("dragon-material sword: full reimbursement minus deductible");
  it.todo("high-enchantment item (>=8): 50% reimbursement then deductible");
  it.todo("dragon + high-enchantment: 50% wins, then deductible");

  // Claim: cap
  it.todo("payout capped at 2x insurance sum; remaining cap tracked");
  it.todo("multiple damages: deductible applies per damaged item");

  // Errors
  it.todo("unknown item type in quote causes error");
  it.todo("claim references item not in policy causes error");
  it.todo("negative damage amount causes error");
});

