   const itemsBasePremium = (items: Item[]): number =>
     sum(
       Array.from(countByType(items), ([type, count]) =>
         typeGroupPremium(type, count),
       ),
     );

   const CURSE_SURCHARGE_RATE = 0.5;
   const HIGH_ENCHANTMENT_RATE = 0.3;
   const HIGH_ENCHANTMENT_THRESHOLD = 5;

   const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
     { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
     {
       applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
       rate: HIGH_ENCHANTMENT_RATE,
     },
   ];

   const itemSurcharge = (item: Item): number => {
     const base = BASE_PREMIUM[item.type];
     return sum(
       SURCHARGE_RULES.map((rule) => (rule.applies(item) ? base * rule.rate : 0)),
     );
   };

   const itemSurcharges = (items: Item[]): number =>
     sum(items.map(itemSurcharge));

   const LOYALTY_DISCOUNT_RATE = 0.2;
   const LOYALTY_YEARS_THRESHOLD = 2;
   const FOLLOWUP_DISCOUNT_RATE = 0.15;

   const isLongStanding = (customer: Customer): boolean =>
     customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

   const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
     isLongStanding(customer) ? -policyBase * LOYALTY_DISCOUNT_RATE : 0;

   const firstInsuranceSurcharge = (policyBase: number): number =>
     policyBase * FIRST_INSURANCE_RATE;

   const followupDiscount = (policyBase: number, isFollowup: boolean): number =>
     isFollowup ? -policyBase * FOLLOWUP_DISCOUNT_RATE : 0;

   const policyModifiers = (
     policyBase: number,
     customer: Customer,
     isFollowup: boolean,
   ): number =>
     firstInsuranceSurcharge(policyBase) +
     loyaltyDiscount(policyBase, customer) +
     followupDiscount(policyBase, isFollowup);

   const quote = (
     step: Step,
     customer: Customer,
     isFollowup: boolean,
   ): { premium: number } => {
     const items = step.items;
     const policyBase = itemsBasePremium(items);
     const total =
       policyBase +
       itemSurcharges(items) +
       policyModifiers(policyBase, customer, isFollowup) +
       PROCESSING_FEE;
     return { premium: roundUpInMHPCOFavor(total) };
   };

   export const runScenario = (input: unknown): unknown => {
     const scenario = input as Scenario;
     const results = scenario.steps.map((step, index) =>
       quote(step, scenario.customer, index > 0),
     );
     return { results };
   };
   ```

4. Errors and fixes:
   - **Test description didn't match expected calculation**: Originally wrote "plain sword yields 105 G" but the spec says first insurance applies to every item. Fixed by updating test name and expectation to 115 G (100 + 10 + 5). Similar fix for amulet (65 → 71).
   - **JS floating-point precision**: 100 * 1.1 = 110.00000000000001 caused Math.ceil to return 116 instead of 115. Fixed with epsilon: `Math.ceil(amount - 1e-9)`.
