import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword yields 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    });
    // 100 base + 10 first insurance + 5 fee = 115
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet yields 71 G (60 base + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for sword + amulet sums base premiums (160 base + 16 + 5 = 181)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // Quote: components and blocks
  it("quote for 2 runes yields 60 G (50 base + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 runes yields 71 G (60 block base + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes yields 115 G (100 base + 10 first ins + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 3 runes + 3 moonstones yields 137 G (120 base × 1.1 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "moonstone" },
          { type: "moonstone" },
          { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Quote: item-level modifiers
  it("cursed sword for newcomer yields 165 G (100 + 50 curse + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("high-enchantment sword (enchantment 5) yields 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 has no high-enchantment surcharge (115 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // Quote: policy-level modifiers
  it("long-standing customer (2+ years) plain sword: 95 G (100 - 20 loyalty + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("second quote in scenario gets 15% follow-up discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // 1st: 100 + 10 + 5 = 115
    // 2nd: 100 + 10 - 15 + 5 = 100
    expect(result).toEqual({
      results: [{ premium: 115 }, { premium: 100 }],
    });
  });

  // Quote: rounding
  it("rounds final premium up: 1 rune (25 base + 2.5 first ins + 5 fee = 32.5 → 33)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "rune" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });

  // Quote: integration
  it.todo("newcomer with cursed sword: premium 165 G");
  it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");

  // Claim: basic
  it.todo("standard claim: damage 500 G on sword yields payout 400 G (minus deductible)");
  it.todo("claim on rune (no enchant/material): damage 200 yields 100 G payout");

  // Claim: special clauses
  it.todo("dragon-material sword: full reimbursement minus deductible");
  it.todo("high-enchantment item (>=8): 50% reimbursement then deductible");
  it.todo("dragon + high-enchantment: 50% wins, then deductible");

  // Claim: cap
  it.todo("payout capped at 2x insurance sum; remaining cap tracked");
  it.todo("multiple damages: deductible applies per damaged item");

  // Errors
  it.todo("unknown item type in quote causes error");
  it.todo("claim references item not in policy causes error");
  it.todo("negative damage amount causes error");
});

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const FP_EPSILON = 1e-9;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

type Item = { type: string; cursed?: boolean; enchantment?: number };
type Customer = { yearsWithMHPCO: number };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: Customer; steps: Step[] };

const sum = (numbers: number[]): number =>
  numbers.reduce((acc, n) => acc + n, 0);

// round up to whole G in MHPCO's favor, using epsilon to fight FP error
const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(amount - FP_EPSILON);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const typeGroupPremium = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * BASE_PREMIUM[type];

const itemsBasePremium = (items: Item[]): number =>
  sum(
    Array.from(countByType(items), ([type, count]) =>
      typeGroupPremium(type, count),
    ),
  );

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
  {
    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
    rate: HIGH_ENCHANTMENT_RATE,
  },
];

const itemSurcharge = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return sum(
    SURCHARGE_RULES.map((rule) => (rule.applies(item) ? base * rule.rate : 0)),
  );
};

const itemSurcharges = (items: Item[]): number =>
  sum(items.map(itemSurcharge));

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOWUP_DISCOUNT_RATE = 0.15;

const isLongStanding = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
  isLongStanding(customer) ? -policyBase * LOYALTY_DISCOUNT_RATE : 0;

const firstInsuranceSurcharge = (policyBase: number): number =>
  policyBase * FIRST_INSURANCE_RATE;

const followupDiscount = (policyBase: number, isFollowup: boolean): number =>
  isFollowup ? -policyBase * FOLLOWUP_DISCOUNT_RATE : 0;

const policyModifiers = (
  policyBase: number,
  customer: Customer,
  isFollowup: boolean,
): number =>
  firstInsuranceSurcharge(policyBase) +
  loyaltyDiscount(policyBase, customer) +
  followupDiscount(policyBase, isFollowup);

const quote = (
  step: Step,
  customer: Customer,
  isFollowup: boolean,
): { premium: number } => {
  const items = step.items;
  const policyBase = itemsBasePremium(items);
  const total =
    policyBase +
    itemSurcharges(items) +
    policyModifiers(policyBase, customer, isFollowup) +
    PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(total) };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step, index) =>
    quote(step, scenario.customer, index > 0),
  );
  return { results };
};

