type Policy = { items: Item[]; remainingCap: number };

const policyInsuranceSum = (items: Item[]): number =>
  sum(items.map((item) => INSURANCE_VALUE[item.type]));

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const claim = (
  step: ClaimStep,
  policies: Policy[],
): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy];
  const payout = sum(step.incident.damages.map(damagePayout));
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const result = quote(step, {
        customer: scenario.customer,
        isFollowup: quoteCount > 0,
      });
      quoteCount++;
      policies.push({
        items: step.items,
        remainingCap: policyInsuranceSum(step.items) * CAP_MULTIPLIER,
      });
      return result;
    }
    return claim(step, policies);
  });
  return { results };
};

