  step: QuoteStep,
  customer: Customer,
  policies: Policy[],
) => {
  const result = quote(step, { customer, isFollowup: policies.length > 0 });
  policies.push(openPolicy(step.items));
  return result;
};

const policyDamagePayout = (policy: Policy, damage: Damage): number => {
  const item = policy.items.find((i) => i.type === damage.itemType) as Item;
  return damagePayout(damage, item);
};

const processClaim = (step: ClaimStep, policies: Policy[]) => {
  const policy = policies[step.policy];
  const payout = sum(step.incident.damages.map((d) => policyDamagePayout(policy, d)));
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

